import React, { useState, useEffect, useCallback } from "react";
import InternshipCard from "../components/InternshipCard";
import InternshipModal from "../components/InternshipModal";
import axios from "axios";
import "./Internship.css";

export default function Internship({ user }) {
  const [internships, setInternships] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [search, setSearch] = useState("");
  const [filter, setFilter] = useState({ category: "", location: "", mode: "" });
  const [showModal, setShowModal] = useState(false);
  const [editData, setEditData] = useState(null);
  const [applications, setApplications] = useState({}); // {internshipId: status}

  const userRole = user?.role;

  const fetchInternships = useCallback(async () => {
    const res = await axios.get("/api/internships");
    setInternships(res.data);
    setFiltered(res.data);
  }, []);

  const fetchApplications = useCallback(async () => {
    if (userRole === "student") {
      const res = await axios.get(`/api/applications/${user._id}`);
      const statusMap = {};
      res.data.forEach(app => statusMap[app.internshipId] = app.status);
      setApplications(statusMap);
    }
  }, [userRole, user._id]);


  useEffect(() => {
    fetchInternships();
    fetchApplications();
  }, []);

  useEffect(() => {
    let result = internships.filter(int => {
      return (
        int.title.toLowerCase().includes(search.toLowerCase()) &&
        (!filter.category || int.category === filter.category) &&
        (!filter.location || int.location === filter.location) &&
        (!filter.mode || int.mode === filter.mode)
      );
    });
    setFiltered(result);
  }, [search, filter, internships]);

  const handleApply = async (internshipId) => {
    await axios.post("/api/applications", {
      internshipId,
      studentId: user._id,
    });
    fetchApplications();
  };

  const handleSave = async (data) => {
    if (editData) {
      await axios.put(`/api/internships/${editData._id}`, data);
    } else {
      await axios.post("/api/internships", data);
    }
    setEditData(null);
    fetchInternships();
  };

  const handleDelete = async (id) => {
    await axios.delete(`/api/internships/${id}`);
    fetchInternships();
  };

  return (
    <div className="internship-page">
      <h2>Internship Opportunities</h2>

      {/* 🔍 Search + Filters */}
      <div className="filters">
        <input
          type="text"
          placeholder="Search by title or company"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />

        <select onChange={(e) => setFilter({ ...filter, category: e.target.value })}>
          <option value="">Category</option>
          <option value="Web Development">Web Development</option>
          <option value="Marketing">Marketing</option>
          <option value="Design">Design</option>
        </select>

        <select onChange={(e) => setFilter({ ...filter, location: e.target.value })}>
          <option value="">Location</option>
          <option value="Remote">Remote</option>
          <option value="Delhi">Delhi</option>
          <option value="Mumbai">Mumbai</option>
        </select>

        <select onChange={(e) => setFilter({ ...filter, mode: e.target.value })}>
          <option value="">Mode</option>
          <option value="Online">Online</option>
          <option value="Offline">Offline</option>
          <option value="Hybrid">Hybrid</option>
        </select>

        {(userRole === "admin" || userRole === "hr") && (
          <button className="add-btn" onClick={() => setShowModal(true)}>
            + Add Internship
          </button>
        )}
      </div>

      {/* 📄 Internship List */}
      <div className="internship-list">
        {filtered.length === 0 && <p>No internships found.</p>}
        {filtered.map((int) => (
          <InternshipCard
            key={int._id}
            internship={int}
            onApply={handleApply}
            onEdit={(data) => {
              setEditData(data);
              setShowModal(true);
            }}
            onDelete={handleDelete}
            userRole={userRole}
            applicationStatus={applications[int._id]}
          />
        ))}
      </div>

      <InternshipModal
        show={showModal}
        onClose={() => {
          setShowModal(false);
          setEditData(null);
        }}
        onSave={handleSave}
        internship={editData}
      />
    </div>
  );
}
